// Dans un n8n Code Node
const posts = $input.all();

// Grouper les posts par subreddit
const postsBySubreddit = {};

for (const post of posts) {
  const subreddit = post.json.subreddit || 'unknown';

  if (!postsBySubreddit[subreddit]) {
    postsBySubreddit[subreddit] = [];
  }

  postsBySubreddit[subreddit].push(post);
}

// Trouver le top post de chaque subreddit
const topPosts = [];

for (const subreddit in postsBySubreddit) {
  const subredditPosts = postsBySubreddit[subreddit];

  const topPost = subredditPosts.reduce((best, current) => {
    const currentScore = current.json.score || 0;
    const bestScore = best.json.score || 0;
    return currentScore > bestScore ? current : best;
  });

  topPosts.push(topPost);
}

return topPosts;

